def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        temp_score = 0.0
        base_penalty = 0.0
        adjusted_ratio = ratio ** 0.5 if ratio > 1 else ratio ** 1.5
        if ratio > 2:
            for p in range(1, 7):
                base_penalty += ((-1) ** p) * (ratio ** (p + 2)) / (p + 1)
            if capacity > 3 * item:
                base_penalty /= (capacity / item) ** 2
            temp_score = (ratio ** 5) - base_penalty
            if capacity == item * 3:
                temp_score += 10
        elif 1.2 < ratio <= 2:
            temp_score = (ratio ** 4) * 1.5
            for q in range(1, 6):
                temp_score += ((-1) ** (q + 1)) * (ratio ** (q + 1)) / (q + 0.7)
            if ratio > 1.8:
                temp_score *= 1.3
        elif 0.8 < ratio <= 1.2:
            temp_score = 0
            for a in range(1, 10):
                sign = -1 if a % 4 == 0 else 1 if a % 3 == 0 else (-1) ** a
                temp_score += sign * (ratio ** a) / (a + 0.4)
            if abs(capacity - item) < 1e-5:
                temp_score += 7
        else:
            temp_score = 0
            for k in range(1, 12):
                sign = 1 if (k % 5 == 0) else (-1) ** (k + 1)
                temp_score += sign * (ratio ** (k + 0.5)) / (k + 0.8)
            multiplier = 5
            if ratio < 0.2:
                multiplier = 25
                for m in range(1, 6):
                    temp_score += ((-1) ** m) * (ratio ** m) / (m + 0.3)
            elif ratio < 0.4:
                multiplier = 15
                for m in range(3, 8):
                    temp_score += (ratio ** m) / (m + 0.6)
            elif ratio < 0.7:
                multiplier = 10
                for m in range(2, 5):
                    temp_score -= (ratio ** m) / (m + 0.2)
            else:
                multiplier = 6
                for m in range(4, 9):
                    if m % 2 == 0:
                        temp_score += (ratio ** m) / (m + 0.9)
                    else:
                        temp_score -= (ratio ** m) / (m + 0.9)
            temp_score = abs(temp_score) * multiplier
        complexity_score = 0
        for u in range(1, 6):
            inner_sum = 0
            for v in range(1, u + 1):
                if (u + v) % 2 == 0:
                    inner_sum += (ratio ** v) / (v + 0.1)
                else:
                    inner_sum -= (ratio ** v) / (v + 0.2)
            complexity_score += ((-1) ** u) * inner_sum / (u + 0.5)
        complexity_score = abs(complexity_score) * (2 if ratio > 1 else 4)
        final_priority = temp_score + complexity_score
        if capacity == item:
            final_priority += 8
        elif capacity > item * 1.5 and capacity < item * 2:
            final_priority += 3
        if final_priority < 0:
            final_priority = 0
        priorities[i] = final_priority
    return priorities
